const Web3 = require('web3');
const web3 = new Web3(new Web3.providers.HttpProvider('https://mainnet.infura.io/v3/YOUR_PROJECT_ID'));

// Wallet configuration with private keys for signing transactions
const wallet = new Web3.eth.accounts.privateKeyToAccount('0xPRIVATE_KEY');
web3.eth.accounts.wallet.add(wallet);

// Function to send ETH
async function sendETH(toAddress, amount) {
  const tx = {
    from: wallet.address,
    to: toAddress,
    value: web3.utils.toWei(amount, 'ether'),
  };
  await web3.eth.sendTransaction(tx);
}

// Function to interact with smart contracts
async function interactWithContract(contractAddress, abi, methodName, args) {
  const contract = new web3.eth.Contract(abi, contractAddress);
  const method = contract.methods[methodName](...args);
  await method.estimateGas();
  const gasLimit = method.gasLimit;
  const gasPrice = web3.utils.toWei('20', 'gwei');
  const tx = {
    from: wallet.address,
    to: contractAddress,
    value: 0,
    gas: gasLimit,
    gasPrice: gasPrice,
  };
  await web3.eth.sendTransaction(tx);
}